contracts/PaymentSplitter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title AgentPaymentSplitter
 * @notice Handles automatic payment distribution to task participants
 */
contract AgentPaymentSplitter is Ownable(msg.sender) {

    struct Split {
        bytes32 taskId;
        address[] payees;
        uint256[] shares;
        uint256 totalShares;
        uint256 totalReleased;
        bool isERC20;
        address token;
    }

    mapping(bytes32 => Split) public splits;
    mapping(bytes32 => mapping(address => uint256)) public released;

    event SplitCreated(bytes32 indexed taskId, address[] payees, uint256[] shares);
    event PaymentReleased(bytes32 indexed taskId, address indexed payee, uint256 amount);
    event ERC20PaymentReleased(bytes32 indexed taskId, address indexed payee, address indexed token, uint256 amount);

    function createSplit(
        bytes32 taskId,
        address[] memory payees,
        uint256[] memory shares,
        bool isERC20,
        address token
    ) external payable onlyOwner {
        require(payees.length == shares.length, "Payees and shares length mismatch");
        require(payees.length > 0, "No payees");

        uint256 totalShares = 0;
        for (uint i = 0; i < shares.length; i++) {
            totalShares += shares[i];
        }

        if (!isERC20) {
            require(msg.value > 0, "No ETH sent");
        }

        splits[taskId] = Split({
            taskId: taskId,
            payees: payees,
            shares: shares,
            totalShares: totalShares,
            totalReleased: 0,
            isERC20: isERC20,
            token: token
        });

        emit SplitCreated(taskId, payees, shares);
    }

    function release(bytes32 taskId, address payable payee) external {
        Split storage split = splits[taskId];
        require(split.payees.length > 0, "Split does not exist");

        uint256 payeeIndex = findPayeeIndex(taskId, payee);
        require(payeeIndex < split.payees.length, "Not a payee");

        uint256 totalReceived = split.isERC20 ? 
            IERC20(split.token).balanceOf(address(this)) + split.totalReleased :
            address(this).balance + split.totalReleased;

        uint256 payment = (totalReceived * split.shares[payeeIndex]) / split.totalShares - released[taskId][payee];
        require(payment > 0, "No payment due");

        released[taskId][payee] += payment;
        split.totalReleased += payment;

        if (split.isERC20) {
            IERC20(split.token).transfer(payee, payment);
            emit ERC20PaymentReleased(taskId, payee, split.token, payment);
        } else {
            payee.transfer(payment);
            emit PaymentReleased(taskId, payee, payment);
        }
    }

    function findPayeeIndex(bytes32 taskId, address payee) internal view returns (uint256) {
        Split storage split = splits[taskId];
        for (uint i = 0; i < split.payees.length; i++) {
            if (split.payees[i] == payee) {
                return i;
            }
        }
        return split.payees.length; // Return out of bounds if not found
    }

    function pendingPayment(bytes32 taskId, address payee) external view returns (uint256) {
        Split storage split = splits[taskId];
        if (split.payees.length == 0) return 0;

        uint256 payeeIndex = findPayeeIndex(taskId, payee);
        if (payeeIndex >= split.payees.length) return 0;

        uint256 totalReceived = split.isERC20 ? 
            IERC20(split.token).balanceOf(address(this)) + split.totalReleased :
            address(this).balance + split.totalReleased;

        return (totalReceived * split.shares[payeeIndex]) / split.totalShares - released[taskId][payee];
    }

    function getSplit(bytes32 taskId) external view returns (Split memory) {
        return splits[taskId];
    }
}

contracts/ReputationVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./AgentRegistry.sol";

/**
 * @title ReputationVault
 * @notice On-chain reputation system for AI agents
 */
contract ReputationVault is Ownable(msg.sender) {

    struct ReputationScore {
        uint256 totalScore;
        uint256 taskCompleted;
        uint256 taskFailed;
        uint256 ratingSum;
        uint256 ratingCount;
        uint256 lastUpdated;
    }

    mapping(bytes32 => ReputationScore) public reputations;
    mapping(bytes32 => mapping(address => bool)) public hasRated;

    AgentRegistry public agentRegistry;

    uint256 public constant MAX_RATING = 5;
    uint256 public constant REPUTATION_DECAY_DAYS = 90;

    event ReputationUpdated(bytes32 indexed agentId, uint256 newScore, string reason);
    event TaskCompleted(bytes32 indexed agentId, bytes32 indexed taskId);
    event TaskFailed(bytes32 indexed agentId, bytes32 indexed taskId);
    event Rated(bytes32 indexed agentId, address indexed rater, uint256 rating);

    constructor(address _agentRegistry) {
        agentRegistry = AgentRegistry(_agentRegistry);
    }

    function recordTaskCompletion(bytes32 agentId, bytes32 taskId) external onlyOwner {
        ReputationScore storage rep = reputations[agentId];
        rep.taskCompleted++;
        rep.totalScore += 10;
        rep.lastUpdated = block.timestamp;

        emit TaskCompleted(agentId, taskId);
        emit ReputationUpdated(agentId, rep.totalScore, "Task completed");
    }

    function recordTaskFailure(bytes32 agentId, bytes32 taskId) external onlyOwner {
        ReputationScore storage rep = reputations[agentId];
        rep.taskFailed++;
        if (rep.totalScore >= 5) {
            rep.totalScore -= 5;
        }
        rep.lastUpdated = block.timestamp;

        emit TaskFailed(agentId, taskId);
        emit ReputationUpdated(agentId, rep.totalScore, "Task failed");
    }

    function rateAgent(bytes32 agentId, uint256 rating) external {
        require(rating > 0 && rating <= MAX_RATING, "Invalid rating");
        require(!hasRated[agentId][msg.sender], "Already rated");

        AgentRegistry.Agent memory agent = agentRegistry.getAgent(agentId);
        require(agent.owner != msg.sender, "Cannot rate own agent");
        require(agent.active, "Agent inactive");

        ReputationScore storage rep = reputations[agentId];
        rep.ratingSum += rating;
        rep.ratingCount++;
        rep.totalScore += rating * 2;
        rep.lastUpdated = block.timestamp;
        hasRated[agentId][msg.sender] = true;

        emit Rated(agentId, msg.sender, rating);
        emit ReputationUpdated(agentId, rep.totalScore, "New rating");
    }

    function getReputation(bytes32 agentId) external view returns (ReputationScore memory) {
        return reputations[agentId];
    }

    function getAverageRating(bytes32 agentId) external view returns (uint256) {
        ReputationScore memory rep = reputations[agentId];
        if (rep.ratingCount == 0) return 0;
        return rep.ratingSum / rep.ratingCount;
    }

    function getSuccessRate(bytes32 agentId) external view returns (uint256) {
        ReputationScore memory rep = reputations[agentId];
        uint256 total = rep.taskCompleted + rep.taskFailed;
        if (total == 0) return 0;
        return (rep.taskCompleted * 100) / total;
    }
}

contracts/TaskCoordinator.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./AgentRegistry.sol";

/**
 * @title TaskCoordinator
 * @notice Manages multi-agent task coordination and workflow
 */
contract TaskCoordinator is Ownable(msg.sender), ReentrancyGuard {

    enum TaskStatus { Open, Assigned, InProgress, Completed, Cancelled }

    struct Task {
        bytes32 taskId;
        address creator;
        string description;
        bytes32[] requiredCapabilities;
        uint256 reward;
        address rewardToken;
        TaskStatus status;
        bytes32[] assignedAgents;
        uint256 createdAt;
        uint256 deadline;
    }

    mapping(bytes32 => Task) public tasks;
    mapping(bytes32 => mapping(bytes32 => bool)) public agentApplications;
    bytes32[] public allTaskIds;

    AgentRegistry public agentRegistry;

    event TaskCreated(bytes32 indexed taskId, address indexed creator, uint256 reward);
    event TaskApplied(bytes32 indexed taskId, bytes32 indexed agentId);
    event TaskAssigned(bytes32 indexed taskId, bytes32[] agentIds);
    event TaskStarted(bytes32 indexed taskId);
    event TaskCompleted(bytes32 indexed taskId);
    event TaskCancelled(bytes32 indexed taskId);

    constructor(address _agentRegistry) {
        agentRegistry = AgentRegistry(_agentRegistry);
    }

    function createTask(
        string memory description,
        bytes32[] memory requiredCapabilities,
        uint256 reward,
        address rewardToken,
        uint256 deadline
    ) external payable returns (bytes32) {
        bytes32 taskId = keccak256(abi.encodePacked(msg.sender, description, block.timestamp));

        require(tasks[taskId].creator == address(0), "Task exists");
        require(deadline > block.timestamp, "Invalid deadline");

        if (rewardToken == address(0)) {
            require(msg.value == reward, "Incorrect ETH sent");
        } else {
            IERC20(rewardToken).transferFrom(msg.sender, address(this), reward);
        }

        tasks[taskId] = Task({
            taskId: taskId,
            creator: msg.sender,
            description: description,
            requiredCapabilities: requiredCapabilities,
            reward: reward,
            rewardToken: rewardToken,
            status: TaskStatus.Open,
            assignedAgents: new bytes32[](0),
            createdAt: block.timestamp,
            deadline: deadline
        });

        allTaskIds.push(taskId);
        emit TaskCreated(taskId, msg.sender, reward);
        return taskId;
    }

    function applyForTask(bytes32 taskId, bytes32 agentId) external {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Open, "Task not open");
        require(block.timestamp < task.deadline, "Deadline passed");

        AgentRegistry.Agent memory agent = agentRegistry.getAgent(agentId);
        require(agent.owner == msg.sender, "Not agent owner");
        require(agent.active, "Agent inactive");

        agentApplications[taskId][agentId] = true;
        emit TaskApplied(taskId, agentId);
    }

    function assignAgents(bytes32 taskId, bytes32[] memory agentIds) external {
        Task storage task = tasks[taskId];
        require(task.creator == msg.sender, "Not task creator");
        require(task.status == TaskStatus.Open, "Task not open");

        for (uint i = 0; i < agentIds.length; i++) {
            require(agentApplications[taskId][agentIds[i]], "Agent did not apply");
        }

        task.assignedAgents = agentIds;
        task.status = TaskStatus.Assigned;
        emit TaskAssigned(taskId, agentIds);
    }

    function startTask(bytes32 taskId) external {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Assigned, "Task not assigned");

        bool isAssignedAgent = false;
        for (uint i = 0; i < task.assignedAgents.length; i++) {
            AgentRegistry.Agent memory agent = agentRegistry.getAgent(task.assignedAgents[i]);
            if (agent.owner == msg.sender) {
                isAssignedAgent = true;
                break;
            }
        }
        require(isAssignedAgent, "Not assigned agent");

        task.status = TaskStatus.InProgress;
        emit TaskStarted(taskId);
    }

    function completeTask(bytes32 taskId) external {
        Task storage task = tasks[taskId];
        require(task.creator == msg.sender, "Not task creator");
        require(task.status == TaskStatus.InProgress, "Task not in progress");

        task.status = TaskStatus.Completed;

        // Distribute rewards
        uint256 rewardPerAgent = task.reward / task.assignedAgents.length;
        for (uint i = 0; i < task.assignedAgents.length; i++) {
            AgentRegistry.Agent memory agent = agentRegistry.getAgent(task.assignedAgents[i]);
            if (task.rewardToken == address(0)) {
                payable(agent.owner).transfer(rewardPerAgent);
            } else {
                IERC20(task.rewardToken).transfer(agent.owner, rewardPerAgent);
            }
        }

        emit TaskCompleted(taskId);
    }

    function getTask(bytes32 taskId) external view returns (Task memory) {
        return tasks[taskId];
    }
}

